<?php
if (($_GET['key'] ?? '') !== 'gk-cpanel-setup-2026') {
    http_response_code(403);
    exit('forbidden');
}

$root = __DIR__;
$lines = ['Gonul Koprusu — feed 500 fix', 'base='.$root, ''];
$files = json_decode(<<<'JSON'
{"app/Services/PremiumPackagesService.php": "", "app/Models/User.php": "", "resources/views/partials/profile-member-badges.blade.php": "", "app/Http/Controllers/Web/SetupController.php": ""}
JSON
, true);

foreach ($files as $rel => $b64) {
    $path = $root.'/'.$rel;
    @mkdir(dirname($path), 0755, true);
    $bytes = base64_decode($b64);
    file_put_contents($path, $bytes);
    $lines[] = 'write '.$rel.' '.strlen($bytes);
}

foreach ([
    'cd '.escapeshellarg($root).' && composer dump-autoload -o --no-interaction 2>&1',
    'cd '.escapeshellarg($root).' && php composer.phar dump-autoload -o --no-interaction 2>&1',
] as $cmd) {
    $out = @shell_exec($cmd);
    if (is_string($out) && trim($out) !== '') {
        $lines[] = 'autoload: '.preg_replace('/\s+/', ' ', trim($out));
        break;
    }
}

try {
    $lines[] = 'PremiumPackagesService: '.(class_exists('App\\Services\\PremiumPackagesService') ? 'ok' : 'YOK');
} catch (Throwable $e) {
    $lines[] = 'PremiumPackagesService: '.$e->getMessage();
}

foreach (glob($root.'/storage/framework/views/*.php') ?: [] as $view) {
    @unlink($view);
}
if (function_exists('opcache_reset')) {
    @opcache_reset();
    $lines[] = 'opcache reset';
}

$log = $root.'/storage/logs/laravel.log';
if (is_file($log)) {
    $tail = @shell_exec('tail -n 50 '.escapeshellarg($log).' 2>/dev/null');
    if (is_string($tail) && trim($tail) !== '') {
        $lines[] = '';
        $lines[] = '--- laravel.log (tail) ---';
        $lines[] = rtrim($tail);
    }
}

$lines[] = '';
$lines[] = 'OK';
header('Content-Type: text/plain; charset=utf-8');
header('Cache-Control: no-store');
echo implode("\n", $lines)."\n";
